sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }

    var user = g_form.getValue('user');
    var fiscalYear = g_form.getValue('fiscal_year');

    if (!user || !fiscalYear) {
        g_form.clearValue('plan');
        return;
    }

    var ga = new GlideAjax('IncentNowClientUtils');
    ga.addParam('sysparm_name', 'getPlan');
    ga.addParam('sysparm_user', user);
    ga.addParam('sysparm_fiscal_year', fiscalYear);

    ga.getXMLAnswer(function(answer) {
        if (answer) {
            g_form.setValue('plan', answer);
        } else {
            g_form.clearValue('plan');
        }
    });


}
